const docId = $input.first().json.body.document_id;
const supabaseUrl = 'https://plbjafwltwpupspmlnip.supabase.co';
const anonKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InBsYmphZndsdHdwdXBzcG1sbmlwIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzI5NjQ1MTYsImV4cCI6MjA4ODU0MDUxNn0.xQRTqPRBmpEwC1pZ3rX4m9wCtbQHx8jQC-dvgtUbNfk';
const headers = { 'apikey': anonKey, 'Authorization': `Bearer ${anonKey}` };

// Get document
const docRes = await this.helpers.httpRequest({ method: 'GET', url: `${supabaseUrl}/rest/v1/rag_documents?id=eq.${docId}&select=*`, headers });
if (!docRes.length) throw new Error('Document not found: ' + docId);
const doc = docRes[0];

// Set status processing
await this.helpers.httpRequest({ method: 'POST', url: `${supabaseUrl}/functions/v1/rag-update-status`, headers: { 'Content-Type': 'application/json' }, body: { document_id: docId, status: 'processing' } });

// Delete old chunks
try { await this.helpers.httpRequest({ method: 'DELETE', url: `${supabaseUrl}/rest/v1/rag_chunks?document_id=eq.${docId}`, headers }); } catch(e) {}

return [{ json: { document_id: docId, source_ref: doc.source_ref, source_type: doc.source_type, mime_type: doc.mime_type, title: doc.title } }];

const MAX_CHUNK = 1000;
const MIN_CHUNK = 400;
const OVERLAP = 100;

const content = $input.first().json.data || $input.first().json.text || '';
const docId = $('Lire Document').first().json.document_id;
const title = $('Lire Document').first().json.title;

function cleanText(text) { return text.replace(/\s+/g, ' ').trim(); }

const lines = content.split('\n');
const rawChunks = [];
let currentChunk = { heading: '', content: '', index: 0 };
let chunkIndex = 0;

for (let i = 0; i < lines.length; i++) {
  const line = lines[i].trim();
  if (!line) continue;

  const headingMatch = line.match(/^(#{1,6})\s+(.+)$/);

  if (headingMatch) {
    if (currentChunk.content.trim()) {
      rawChunks.push({
        index: chunkIndex++,
        content: cleanText(currentChunk.content),
        chunk_size: cleanText(currentChunk.content).length
      });
    }
    currentChunk = { heading: line, content: line + ' ', index: chunkIndex };
  } else if (line.match(/^[-=]{3,}$/)) {
    continue;
  } else {
    currentChunk.content += line + ' ';
  }
}

if (currentChunk.content.trim()) {
  rawChunks.push({
    index: chunkIndex,
    content: cleanText(currentChunk.content),
    chunk_size: cleanText(currentChunk.content).length
  });
}

if (rawChunks.length === 0) {
  rawChunks.push({ index: 0, content: cleanText(content), chunk_size: cleanText(content).length });
}

// Split oversized chunks at sentence boundaries
const processedChunks = [];
for (const chunk of rawChunks) {
  if (chunk.chunk_size <= MAX_CHUNK) {
    processedChunks.push(chunk);
  } else {
    let remainingText = chunk.content;
    while (remainingText.length > 0) {
      if (remainingText.length <= MAX_CHUNK) {
        processedChunks.push({ content: remainingText, chunk_size: remainingText.length });
        break;
      }
      const textToSplit = remainingText.substring(0, MAX_CHUNK);
      let breakPoint = MAX_CHUNK;
      const sentenceEndings = ['. ', '! ', '? ', '.\n'];
      let bestBreak = -1;
      for (const ending of sentenceEndings) {
        const lastIndex = textToSplit.lastIndexOf(ending);
        if (lastIndex > bestBreak && lastIndex > MAX_CHUNK * 0.7) bestBreak = lastIndex + ending.length;
      }
      if (bestBreak > 0) breakPoint = bestBreak;
      else { const lastSpace = textToSplit.lastIndexOf(' '); if (lastSpace > MAX_CHUNK * 0.7) breakPoint = lastSpace + 1; }
      processedChunks.push({ content: remainingText.substring(0, breakPoint).trim(), chunk_size: remainingText.substring(0, breakPoint).trim().length });
      remainingText = remainingText.substring(breakPoint).trim();
    }
  }
}

// Merge small chunks
const finalChunks = [];
let i = 0;
while (i < processedChunks.length) {
  const cur = processedChunks[i];
  if (cur.chunk_size < MIN_CHUNK) {
    if (i + 1 < processedChunks.length) {
      const next = processedChunks[i + 1];
      if (cur.chunk_size + next.chunk_size + 1 <= MAX_CHUNK) {
        processedChunks[i + 1] = { content: cur.content + ' ' + next.content, chunk_size: cur.content.length + next.content.length + 1 };
        i++; continue;
      }
    }
    if (finalChunks.length > 0) {
      const prev = finalChunks[finalChunks.length - 1];
      if (prev.chunk_size + cur.chunk_size + 1 <= MAX_CHUNK) {
        prev.content += ' ' + cur.content;
        prev.chunk_size = prev.content.length;
        i++; continue;
      }
    }
  }
  finalChunks.push(cur);
  i++;
}

// Add overlap
const result = [];
for (let j = 0; j < finalChunks.length; j++) {
  let chunkText = finalChunks[j].content;
  if (j > 0) chunkText = finalChunks[j-1].content.slice(-OVERLAP) + ' ... ' + chunkText;
  result.push({ json: { chunk_content: chunkText, full_document: content.substring(0, 3000), document_id: docId, title: title, chunk_index: j } });
}

return result;

const docId = $('Lire Document').first().json.document_id;
const supabaseUrl = 'https://plbjafwltwpupspmlnip.supabase.co';

await this.helpers.httpRequest({ method: 'POST', url: `${supabaseUrl}/functions/v1/rag-update-status`, headers: { 'Content-Type': 'application/json' }, body: { document_id: docId, status: 'ready' } });

return [{ json: { success: true, document_id: docId } }];
